"""Continue fetching missing papers and BibTeX entries."""

import json
import time
import urllib.request
import urllib.parse
import re
import os
import html

PAPERS_FILE = "/tmp/isolated_workspace_1091/context/paper_title.md"
CACHE_FILE = "/tmp/isolated_workspace_1091/dblp_cache.json"

def load_papers(filepath):
    papers = []
    with open(filepath, 'r') as f:
        for line in f:
            line = line.strip()
            m = re.match(r'\[(\d+)\]\s+(.*)', line)
            if m:
                papers.append((int(m.group(1)), m.group(2).strip()))
    return papers

def dblp_search(query, retries=3, delay=3):
    url = f"https://dblp.org/search/publ/api?q={urllib.parse.quote(query)}&format=json&h=5"
    for attempt in range(retries):
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=20) as resp:
                data = json.loads(resp.read().decode())
                return data.get("result", {}).get("hits", {}).get("hit", [])
        except Exception as e:
            print(f"  DBLP error: {e}")
            time.sleep(delay * (attempt + 1))
    return []

def dblp_get_bibtex(key, retries=3, delay=3):
    url = f"https://dblp.org/rec/{key}.bib?param=1"
    for attempt in range(retries):
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=20) as resp:
                bibtex = resp.read().decode()
                if bibtex.strip().startswith("@"):
                    return bibtex.strip()
        except Exception as e:
            print(f"  BibTeX fetch error for {key}: {e}")
            time.sleep(delay * (attempt + 1))
    return None

def title_similarity(t1, t2):
    t1_words = set(re.sub(r'[^a-z0-9\s]', '', t1.lower()).split())
    t2_words = set(re.sub(r'[^a-z0-9\s]', '', t2.lower()).split())
    if not t1_words or not t2_words:
        return 0
    stop = {'the', 'a', 'an', 'of', 'for', 'in', 'and', 'on', 'with', 'to', 'from', 'by'}
    t1_clean = t1_words - stop
    t2_clean = t2_words - stop
    if not t1_clean:
        t1_clean = t1_words
    if not t2_clean:
        t2_clean = t2_words
    intersection = t1_clean & t2_clean
    return len(intersection) / max(len(t1_clean), len(t2_clean))

def load_cache():
    if os.path.exists(CACHE_FILE):
        with open(CACHE_FILE, 'r') as f:
            return json.load(f)
    return {}

def save_cache(cache):
    with open(CACHE_FILE, 'w') as f:
        json.dump(cache, f, indent=2)

def main():
    papers = load_papers(PAPERS_FILE)
    cache = load_cache()

    # Papers to search (not in cache or found but no bibtex)
    to_search = []
    for num, title in papers:
        cache_key = title.strip().lower()
        if cache_key not in cache:
            to_search.append((num, title, "not_cached"))
        elif not cache[cache_key].get("bibtex") and cache[cache_key].get("key"):
            to_search.append((num, title, "need_bibtex"))
        elif not cache[cache_key].get("bibtex") and cache[cache_key].get("source") == "not_found":
            to_search.append((num, title, "not_found"))

    print(f"Papers needing work: {len(to_search)}")
    for num, title, reason in to_search:
        print(f"  [{num}] {reason}: {title[:60]}")

    for idx, (num, title, reason) in enumerate(to_search):
        cache_key = title.strip().lower()

        if reason == "need_bibtex":
            key = cache[cache_key].get("key", "")
            print(f"[{num}] Fetching BibTeX for key={key}...")
            bibtex = dblp_get_bibtex(key)
            time.sleep(2)
            if bibtex:
                cache[cache_key]["bibtex"] = bibtex
                cache[cache_key]["source"] = "dblp_bibtex_retry"
                print(f"  Got BibTeX!")
            else:
                print(f"  Still no BibTeX")
            save_cache(cache)
            continue

        # Search DBLP
        print(f"[{num}] Searching: {title[:70]}...")
        search_query = title[:120]
        hits = dblp_search(search_query)
        time.sleep(2)

        best_hit = None
        best_score = 0
        for hit in hits:
            info = hit.get("info", {})
            hit_title = html.unescape(info.get("title", ""))
            score = title_similarity(title, hit_title)
            if score > best_score:
                best_score = score
                best_hit = hit

        # Also try shorter query if no good match
        if best_score < 0.3 and len(title.split()) > 5:
            short_query = " ".join(title.split()[:7])
            print(f"  Retrying shorter: {short_query[:60]}...")
            hits2 = dblp_search(short_query)
            time.sleep(2)
            for hit in hits2:
                info = hit.get("info", {})
                hit_title = html.unescape(info.get("title", ""))
                score = title_similarity(title, hit_title)
                if score > best_score:
                    best_score = score
                    best_hit = hit

        if best_hit and best_score > 0.25:
            info = best_hit.get("info", {})
            key = info.get("key", "")
            found_title = html.unescape(info.get("title", ""))
            print(f"  Found (score={best_score:.2f}): {found_title[:50]}... key={key}")

            bibtex = dblp_get_bibtex(key) if key else None
            time.sleep(2)

            cache[cache_key] = {
                "title": title,
                "found_title": found_title,
                "key": key,
                "bibtex": bibtex,
                "score": best_score,
                "source": "dblp" if bibtex else "found_no_bibtex"
            }
        else:
            print(f"  No match (best={best_score:.2f})")
            cache[cache_key] = {"title": title, "bibtex": None, "source": "not_found"}

        save_cache(cache)

    # Also fix paper 13 (Proximal Policy Optimization - wrong match)
    ppo_key = "proximal policy optimization algorithms"
    if ppo_key in cache and cache[ppo_key].get("key") == "conf/bigcomp/ChenSLCH23":
        print("\nFixing PPO (paper 13) - wrong match...")
        hits = dblp_search("Proximal Policy Optimization Algorithms Schulman")
        time.sleep(2)
        for hit in hits:
            info = hit.get("info", {})
            hit_title = html.unescape(info.get("title", ""))
            if "proximal policy optimization" in hit_title.lower() and "schulman" in str(info.get("authors", "")).lower():
                key = info.get("key", "")
                bibtex = dblp_get_bibtex(key) if key else None
                time.sleep(2)
                cache[ppo_key] = {
                    "title": "Proximal Policy Optimization Algorithms",
                    "found_title": hit_title,
                    "key": key,
                    "bibtex": bibtex,
                    "score": 1.0,
                    "source": "dblp_fixed"
                }
                print(f"  Fixed PPO: {hit_title} key={key}")
                save_cache(cache)
                break

if __name__ == "__main__":
    main()
