        }

        cache[cache_key] = results[num]
        save_cache(cache)
        print(f"  Found: {best.get('title', '?')[:50]}... (doi={doi})")

    # Now compile BibTeX file
    seen_titles = set()
    bibtex_entries = []
    not_found = []

    for num in sorted(results.keys()):
        r = results[num]
        title_for_dedup = r.get("found_title", r.get("title", "")).strip().lower()

        # Normalize for dedup
        dedup_key = re.sub(r'[^a-z0-9]', '', title_for_dedup)
        if dedup_key in seen_titles:
            print(f"Skipping duplicate: [{num}] {r.get('title', '')[:60]}")
            continue
        seen_titles.add(dedup_key)

        if r.get("bibtex"):
